fn test_is_corvia_hook_bash() {
        let entry = json!({
            "hooks": [{"command": "bash .claude/hooks/record-session-start.sh"}]
        });
        assert!(is_corvia_hook(&entry));
    }
fn test_is_corvia_hook_rust() {
        let entry = json!({
            "hooks": [{"command": "corvia hooks run --event SessionStart"}]
        });
        assert!(is_corvia_hook(&entry));
    }
